-- Ricekit generated colorscheme
-- Do not edit — regenerated on theme apply

vim.cmd("hi clear")
if vim.fn.exists("syntax_on") then
  vim.cmd("syntax reset")
end
vim.g.colors_name = "ricekit"
vim.o.termguicolors = true

local hi = function(group, opts)
  vim.api.nvim_set_hl(0, group, opts)
end

-- Core UI
hi("Normal", { fg = "{{foreground}}", bg = "{{background}}" })
hi("NormalFloat", { fg = "{{foreground}}", bg = "{{surface}}" })
hi("FloatBorder", { fg = "{{border}}", bg = "{{surface}}" })
hi("CursorLine", { bg = "{{surface}}" })
hi("CursorColumn", { bg = "{{surface}}" })
hi("ColorColumn", { bg = "{{surface}}" })
hi("LineNr", { fg = "{{bright_black}}" })
hi("CursorLineNr", { fg = "{{accent}}", bold = true })
hi("SignColumn", { bg = "{{background}}" })
hi("FoldColumn", { fg = "{{bright_black}}", bg = "{{background}}" })
hi("Folded", { fg = "{{muted}}", bg = "{{surface}}" })

-- Selection & Search
hi("Visual", { bg = "{{blend(background, blue, 30%)}}" })
hi("VisualNOS", { bg = "{{blend(background, blue, 30%)}}" })
hi("Search", { fg = "{{background}}", bg = "{{yellow}}" })
hi("IncSearch", { fg = "{{background}}", bg = "{{accent}}" })
hi("CurSearch", { fg = "{{background}}", bg = "{{accent}}" })
hi("Substitute", { fg = "{{background}}", bg = "{{red}}" })

-- Status & Tab line
hi("StatusLine", { fg = "{{foreground}}", bg = "{{surface}}" })
hi("StatusLineNC", { fg = "{{muted}}", bg = "{{surface}}" })
hi("TabLine", { fg = "{{muted}}", bg = "{{surface}}" })
hi("TabLineFill", { bg = "{{surface}}" })
hi("TabLineSel", { fg = "{{foreground}}", bg = "{{background}}" })
hi("WinSeparator", { fg = "{{border}}" })

-- Popup menu
hi("Pmenu", { fg = "{{foreground}}", bg = "{{surface}}" })
