hi("MoreMsg", { fg = "{{info}}" })
hi("ModeMsg", { fg = "{{accent}}", bold = true })
hi("Question", { fg = "{{info}}" })
hi("Title", { fg = "{{accent}}", bold = true })
hi("Directory", { fg = "{{blue}}" })

-- Diff
hi("DiffAdd", { bg = "{{blend(background, green, 15%)}}" })
hi("DiffChange", { bg = "{{blend(background, yellow, 15%)}}" })
hi("DiffDelete", { fg = "{{red}}", bg = "{{blend(background, red, 10%)}}" })
hi("DiffText", { bg = "{{blend(background, yellow, 30%)}}" })

-- Diagnostics
hi("DiagnosticError", { fg = "{{error}}" })
